    // Map to store sum -> count of representations
    // Using Map is necessary because the keys (sums) can be large numbers up to 10^9.
    const sumCounts = new Map();

    // Determine A_max: a^3 + a^3 <= n => 2*a^3 <= n => a^3 <= n/2
