    let aMax = Math.floor(Math.cbrt(n / 2));

    if (aMax < 1) {
        return [];
    }

    // Loop for 'a'
    for (let a = 1; a <= aMax; a++) {
        // Calculate a^3
        const a3 = a * a * a;

        // Determine B_max for current 'a': a^3 + b^3 <= n => b^3 <= n - a^3
