    for (let a = 1; a <= aMax; a++) {
        // Calculate a^3. Use BigInt if n exceeded 2^53, but since n <= 10^9, standard Number is fine.
        const a3 = a * a * a;

        // Determine B_max for current 'a': a^3 + b^3 <= n => b^3 <= n - a^3
